def fibonacci_tabulation(n):
    if n < 0:
        raise ValueError("Girdi negatif olamaz.")
    if n == 0:
        return 0
    if n == 1:
        return 1

    dp = [0] * (n + 1)
    dp[1] = 1

    for i in range(2, n + 1):
        dp[i] = dp[i-1] + dp[i-2]

    return dp[n]

if __name__ == '__main__':
    # Örnek kullanım
    for i in range(10):
        print(f"fibonacci_tabulation({i}) = {fibonacci_tabulation(i)}")

    # Daha büyük bir sayı için
    n_large = 20
    print(f"\nfibonacci_tabulation({n_large}) = {fibonacci_tabulation(n_large)}")

    # F(0) ve F(1) özel durumları
    print(f"\nfibonacci_tabulation(0) = {fibonacci_tabulation(0)}")
    print(f"fibonacci_tabulation(1) = {fibonacci_tabulation(1)}")
